function cleanText(value) {
  if (value === null || value === undefined) return null;

  let s = String(value);

  s = s.replace(/\r/g, "");
  s = s.replace(/<br\s*\/?>/gi, " ");
  s = s.replace(/<[^>]+>/g, " ");
  s = s.replace(/<ref[^>]*>[\s\S]*?<\/ref>/gi, " ");
  s = s.replace(/<ref[^\/]*\/>/gi, " ");

  // [[A|B]] -> B
  s = s.replace(/\[\[(?:[^|\]]+\|)?([^\]]+)\]\]/g, "$1");

  // fechas wiki
  s = s.replace(/\{\{fecha\|(\d{1,2})\|(\d{1,2})\|(\d{4})\}\}/gi, (_, d, m, y) => {
    return `${y}-${String(m).padStart(2, "0")}-${String(d).padStart(2, "0")}`;
  });

  s = s.replace(/\{\{fecha de inicio\|(\d{1,2})\|(\d{1,2})\|(\d{4})\}\}/gi, (_, d, m, y) => {
    return `${y}-${String(m).padStart(2, "0")}-${String(d).padStart(2, "0")}`;
  });

  s = s.replace(/\{\{esd\}\}/gi, "");
  s = s.replace(/\{\{small\|([^}]*)\}\}/gi, "$1");
  s = s.replace(/\{\{sin negrita\|([^}]*)\}\}/gi, "$1");
  s = s.replace(/\{\{nowrap\|([^}]*)\}\}/gi, "$1");
  s = s.replace(/\{\{color\|[^|]+\|([^}]*)\}\}/gi, "$1");
  s = s.replace(/\{\{tc negro\|[^|]+\|([^}]*)\}\}/gi, "$1");

  s = s.replace(/'''/g, "");
  s = s.replace(/''/g, "");
  s = s.replace(/&nbsp;/g, " ");
  s = s.replace(/\s+/g, " ").trim();

  return s || null;
}

function normalizeTeam(value) {
