    .replace(/^PSV Eindhoven$/i, "PSV Eindhoven")
    .replace(/^Club Brujas$/i, "Brujas");
}

function extractParam(block, key) {
  const escapedKey = key.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const regex = new RegExp(
    `\\|\\s*${escapedKey}\\s*=([\\s\\S]*?)(?=\\n\\|\\s*[^=]+=|\\n\\}\\}|$)`,
    "i"
  );
  const m = block.match(regex);
  return m ? m[1].trim() : null;
}

function parseScore(scoreRaw) {
  const s = cleanText(scoreRaw);
  if (!s) return null;

  const m = s.match(/(\d+)\s*[:\\-–]\s*(\d+)/);
  if (!m) return null;

  return {
    score: `${parseInt(m[1], 10)}-${parseInt(m[2], 10)}`,
    home_score: parseInt(m[1], 10),
    away_score: parseInt(m[2], 10),
  };
}

function parseAttendance(raw) {
  const s = cleanText(raw);
  if (!s) return null;
  const digits = s.replace(/[^\d]/g, "");
  return digits ? parseInt(digits, 10) : null;
}

function parseFinalDateTime(raw) {
  const s = cleanText(raw);
  if (!s) return { date: null, time: null };

  let date = null;
  let time = null;

  const months = {
    enero: "01",
    febrero: "02",
    marzo: "03",
    abril: "04",
    mayo: "05",
    junio: "06",
    julio: "07",
    agosto: "08",
    septiembre: "09",
    setiembre: "09",
    octubre: "10",
    noviembre: "11",
    diciembre: "12",
  };

  const m = s.match(/(\d{1,2}) de ([a-záéíóú]+) de (\d{4})(?:,\s*(\d{1,2}:\d{2}))?/i);
  if (m) {
    const dd = String(m[1]).padStart(2, "0");
    const mm = months[m[2].toLowerCase()] || null;
    const yyyy = m[3];
    time = m[4] || null;

    if (mm) date = `${yyyy}-${mm}-${dd}`;
  }

  return { date, time };
}

function detectStageFromTitle(title) {
  const t = String(title || "").toLowerCase();

  if (t.includes("octavos")) return "round_of_16";
  if (t.includes("cuartos")) return "quarter_final";
  if (t.includes("semifinal")) return "semi_final";
