  if (/^\d{4}\/\d{2}$/.test(str)) return str;
  if (/^\d{4}-\d{2}$/.test(str)) return str.replace("-", "/");

  const m = str.match(/^(\d{4})[\/-](\d{4})$/);
  if (m) return `${m[1]}/${m[2].slice(-2)}`;

  return str;
}

