function resolveTeam(rawName) {
  let key = normalize(rawName);
  if (!key) return null;

  if (aliases[key]) {
    key = aliases[key];
  }

  let found = teamMap.get(key);
  if (found) return found;

  for (const [teamKey, teamValue] of teamMap.entries()) {
    if (teamKey.includes(key) || key.includes(teamKey)) {
      return teamValue;
    }
  }

  return null;
}

